class Solution {
public:
    bool validateStackSequences(vector<char>& pushed, vector<char>& popped) {
        stack<int> stack;
        for (int i = 0; i < pushed.size(); i++) {
            stack.push(pushed[i]);
        }
        for (int i = 0; i < popped.size(); i++) {
            while (!stack.empty() && stack.top() == popped[i]) {
                stack.pop();
            }
            if (stack.empty() || stack.top() != popped[i]) {
                return false;
            }
        }
        return !stack.empty();
    }
};

int main() {
    Solution solution;
    vector<char> pushed = {'2', '3', '+'};
    vector<char> popped = {'3', '+', '2'};
    cout << (solution.validateStackSequences(pushed, popped) ? '1' : '0') << endl;
    return 0;
}
